import org.openjdk.jmh.runner.Runner;
import org.openjdk.jmh.runner.RunnerException;
import org.openjdk.jmh.runner.options.OptionsBuilder;

abstract class ThemeTerminalOperatorBenchmarkBase {

	private static final String COUNT_BINDING = "count";
	private static final File STORE_ROOT = new File("target", "lmdb-theme-terminal-operators");

	private SailRepository repository;
	private LmdbStore store;
	private long expectedCount;

	@Setup(Level.Trial)
	public void setup() throws IOException {
		var dataDir = new File(STORE_ROOT, getClass().getSimpleName());
		FileUtils.deleteDirectory(dataDir);
		if (!dataDir.exists() && !dataDir.mkdirs()) {
			throw new IOException("Unable to create LMDB benchmark directory: " + dataDir);
		}

		var storeConfig = createNoSpillConfig();
		store = new LmdbStore(dataDir, storeConfig);
		repository = new SailRepository(store);

		loadThemeData();
		expectedCount = executeCountQuery(expectedCountQuery());
	}

	private LmdbStoreConfig createNoSpillConfig() {
		var config = ConfigUtil.createConfig();
		// Keep query solution caches in-memory so these benchmarks measure LMDB + soft-reference pressure, not
		// spillover.
		config.setIterationCacheSyncThreshold(0);
		return config;
	}

	private void loadThemeData() throws IOException {
		try (var connection = repository.getConnection()) {
			for (Theme theme : Theme.values()) {
				connection.begin(IsolationLevels.NONE);
				ThemeDataSetGenerator.generate(theme, new RDFInserter(connection));
				connection.commit();
			}
		}
	}

	private long executeCountQuery(String queryString) {
		try (var connection = repository.getConnection();
				var result = connection.prepareTupleQuery(queryString).evaluate()) {
			if (!result.hasNext()) {
				throw new IllegalStateException("Expected one count row for query: " + queryString);
			}

			var countValue = result.next().getValue(COUNT_BINDING);
			if (!(countValue instanceof Literal)) {
				throw new IllegalStateException("Expected literal count for query: " + queryString);
			}

			if (result.hasNext()) {
				throw new IllegalStateException("Expected one count row for query: " + queryString);
			}

			return ((Literal) countValue).longValue();
		}
	}

	protected final long executeBenchmarkQuery() {
		try (var connection = repository.getConnection();
				var result = connection.prepareTupleQuery(benchmarkQuery()).evaluate()) {
			long actualCount = result.stream().count();
			if (actualCount != expectedCount) {
				throw new IllegalStateException(
						"Unexpected row count for " + getClass().getSimpleName() + ": expected " + expectedCount
								+ " but got " + actualCount);
			}
			return actualCount;
		}
	}

	protected final void assertNoSpillAndExpectedCount() {
		assertEquals(0L, store.getIterationCacheSyncThreshold(), "Expected spill-to-disk to be disabled");
		assertEquals(expectedCount, executeBenchmarkQuery(), "Unexpected row count");
	}

	protected abstract String benchmarkQuery();

	protected abstract String expectedCountQuery();

	@TearDown(Level.Trial)
	public void tearDown() {
		if (repository != null) {
			repository.shutDown();
			repository = null;
		}
		store = null;
	}

	protected static void runBenchmark(Class<?> benchmarkClass) throws RunnerException {
		new Runner(new OptionsBuilder()
				.include(benchmarkClass.getSimpleName())
				.forks(1)
				.build()).run();
	}
}
